import { type ReactNode } from 'react';

import { charsFontWidth12pixelsSize500Map } from '../../text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../text-ellipsis/truncate-string.js';
import { VALUE_MARKER_WIDTH } from '../components/canvas/renderers/value-marker-renderer/constants.js';
import {
  MARKER_CONTENT_TO_BORDER_PADDING,
  MARKER_RADIUS,
} from '../constants.js';
import { MarkerCoords } from '../types/marker-coords.js';

export const calculateValueMarkerCoordinates = (
  content: ReactNode,
  originalX: number,
  trackWidth: number,
): MarkerCoords => {
  let expandedContentWidth = 0;
  if (typeof content === 'string') {
    expandedContentWidth = calculateWidth(
      content,
      charsFontWidth12pixelsSize500Map,
    );
  }

  const widthNeededToRenderText =
    expandedContentWidth + MARKER_CONTENT_TO_BORDER_PADDING * 2;

  if (widthNeededToRenderText > VALUE_MARKER_WIDTH) {
    const halfWidthText = widthNeededToRenderText / 2;

    // expand center
    const x0 = originalX - halfWidthText;
    const x1 = originalX + halfWidthText;

    const overflowsLeft = x0 < 0;
    const overflowsRight = x1 > trackWidth;

    const canExpandCenter = !overflowsLeft && !overflowsRight;

    if (canExpandCenter) {
      return [x0, x1];
    }

    return calculateMarkerExpandToSideCoordinates(
      originalX,
      widthNeededToRenderText,
      trackWidth,
    );
  }

  const overflowsLeft = originalX - MARKER_RADIUS < 0;
  const overflowsRight = originalX + MARKER_RADIUS > trackWidth;

  let x0 = originalX - MARKER_RADIUS;
  let x1 = originalX + MARKER_RADIUS;

  if (overflowsLeft) {
    x0 = 0;
    x1 = VALUE_MARKER_WIDTH;
  } else if (overflowsRight) {
    x0 = trackWidth - VALUE_MARKER_WIDTH;
    x1 = trackWidth;
  }

  return [x0, x1];
};

export const calculateRangeMarkerCoordinates = (
  content: ReactNode,
  originalX: number,
  originalWidth: number,
  trackWidth: number,
  textOverflow: 'expand' | 'truncate',
): MarkerCoords => {
  if (textOverflow === 'expand') {
    let expandedContentWidth = 0;
    if (typeof content === 'string') {
      expandedContentWidth = calculateWidth(
        content,
        charsFontWidth12pixelsSize500Map,
      );
    }

    const widthNeededToRenderText =
      expandedContentWidth + MARKER_CONTENT_TO_BORDER_PADDING * 2;

    if (widthNeededToRenderText > originalWidth) {
      const halfWidthText = widthNeededToRenderText / 2;
      // expand center

      const center = originalWidth / 2 + originalX;
      const x0 = center - halfWidthText;
      const x1 = center + halfWidthText;

      const overflowsLeft = x0 < 0;
      const overflowsRight = x1 > trackWidth;

      const canExpandCenter = !overflowsLeft && !overflowsRight;

      if (canExpandCenter) {
        return [x0, x1];
      }

      return calculateMarkerExpandToSideCoordinates(
        originalX,
        widthNeededToRenderText,
        trackWidth,
      );
    }
  }

  return [originalX, originalX + originalWidth];
};

export const calculateMarkerExpandToSideCoordinates = (
  originalX: number,
  contentWidth: number,
  trackWidth: number,
): MarkerCoords => {
  const leftSpace = originalX;
  const rightSpace = trackWidth - originalX;

  let x0;
  let x1;

  if (leftSpace > rightSpace) {
    // expand left
    x0 = Math.max(originalX - contentWidth, 0);
    x1 = originalX;
  } else {
    // expand right
    x0 = originalX;
    x1 = Math.min(originalX + contentWidth, trackWidth);
  }

  return [x0, x1];
};
